import{z as t}from"zod";export const ChapterStatusSchema=t.enum(["card-generated","drafting","drafted","auditing","audit-passed","audit-failed","state-degraded","revising","ready-for-review","approved","rejected","published","imported"]),TokenUsageSchema=t.object({promptTokens:t.number().int().default(0),completionTokens:t.number().int().default(0),totalTokens:t.number().int().default(0)}),LengthTelemetrySchema=t.object({targetWords:t.number().int().min(1),actualWords:t.number().int().min(0),charCount:t.number().int().min(0),cjkChars:t.number().int().min(0),withinRange:t.boolean().default(!0),correctionsApplied:t.number().int().min(0).default(0)}),ChapterMetaSchema=t.object({number:t.number().int().min(1),title:t.string(),status:ChapterStatusSchema,wordCount:t.number().int().default(0),createdAt:t.string().datetime(),updatedAt:t.string().datetime(),auditIssues:t.array(t.string()).default([]),lengthWarnings:t.array(t.string()).default([]),reviewNote:t.string().optional(),detectionScore:t.number().min(0).max(1).optional(),detectionProvider:t.string().optional(),detectedAt:t.string().datetime().optional(),lengthTelemetry:LengthTelemetrySchema.optional(),tokenUsage:TokenUsageSchema.optional()}),ChapterSchema=ChapterMetaSchema.extend({bookId:t.string().min(1),body:t.string().default(""),intent:t.string().optional(),contextHash:t.string().optional()});
